const crypto = require('crypto');
const input = $input.first().json;
const headers = input.headers || {};
const body = input.body || {};
const expectedSecret = process.env.SIGAF_SIGN_REQUEST_SECRET || 'CHANGE_ME';
const receivedSecret = headers['x-sigaf-sign-request-secret'] || headers['X-Sigaf-Sign-Request-Secret'] || '';
if (receivedSecret !== expectedSecret) {
  throw new Error(`[SIGAF] Unauthorized sign request. eventId=${body.eventId || 'unknown'}`);
}
const hmacSecret = process.env.SIGAF_SIGN_HMAC_SECRET || '';
const receivedSignature = headers['x-sigaf-signature'] || headers['X-Sigaf-Signature'] || '';
if (hmacSecret && receivedSignature) {
  const expectedSignature = 'sha256=' + crypto.createHmac('sha256', hmacSecret).update(JSON.stringify(body)).digest('hex');
  if (receivedSignature !== expectedSignature) {
    throw new Error(`[SIGAF] Invalid HMAC signature. eventId=${body.eventId || 'unknown'}`);
  }
}
return [{ json: body }];

function required(value, label) {
  if (!value) throw new Error(`${label} requerido`);
  return value;
}
const body = $input.first().json;
const normalized = {
  eventType: required(body.eventType, 'eventType'),
  eventId: required(body.eventId, 'eventId'),
  sigafRequestId: required(body.sigafRequestId, 'sigafRequestId'),
  correlationId: body.correlationId || body.sigafRequestId,
  idSolicitud: body.idSolicitud || body.correlationId || body.sigafRequestId,
  documentToSign: {
    googleDocId: required(body.documentToSign?.googleDocId, 'documentToSign.googleDocId'),
    googleDocUrl: body.documentToSign?.googleDocUrl || '',
    originalDriveFileId: body.documentToSign?.originalDriveFileId || ''
  },
  emailContext: {
    messageId: required(body.emailContext?.messageId, 'emailContext.messageId'),
    threadId: required(body.emailContext?.threadId, 'emailContext.threadId'),
    senderEmail: required(body.emailContext?.senderEmail, 'emailContext.senderEmail'),
    senderName: body.emailContext?.senderName || '',
    subject: body.emailContext?.subject || 'Solicitud F-AF-039 firmada'
  },
  signature: {
    requestedByName: required(body.signature?.requestedByName, 'signature.requestedByName'),
    requestedByEmail: required(body.signature?.requestedByEmail, 'signature.requestedByEmail'),
    signatureRole: body.signature?.signatureRole || 'RESPONSABLE_ACTIVOS_FIJOS',
    signatureImageFileId: required(body.signature?.signatureImageFileId, 'signature.signatureImageFileId'),
    signatureAnchor: body.signature?.signatureAnchor || 'FIRMA DEL RESPONSABLE ACTIVOS FIJOS'
  },
  summary: body.summary || {}
};
return [{ json: normalized }];

const signRequest = $('Normalizar solicitud de firma').first().json;
const sigafRequest = $input.first().json;
const blockedStatuses = ['FIRMADA', 'RESPUESTA_ENVIADA', 'ERROR_FIRMA', 'ERROR_ENVIO_RESPUESTA', 'REQUIERE_REVISION_MANUAL'];
if (blockedStatuses.includes(sigafRequest.status)) {
  throw new Error(`Solicitud ${signRequest.sigafRequestId} no firmable en estado ${sigafRequest.status}`);
}
const savedGoogleDocId = sigafRequest.formData?.document?.googleDocId || sigafRequest.formData?.googleDocId;
if (savedGoogleDocId && savedGoogleDocId !== signRequest.documentToSign.googleDocId) {
  throw new Error(`googleDocId no coincide con SIGAF. payload=${signRequest.documentToSign.googleDocId}, sigaf=${savedGoogleDocId}`);
}
return [{ json: { ...signRequest, sigafRequest } }];
